// Dedup safety net — filter out already-processed emails
// The Outlook Trigger tracks new-since-last-poll automatically,
// but this prevents reprocessing if trigger re-delivers an email.
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedIds) staticData.processedIds = [];

const items = $input.all();
const newItems = items.filter(item => !staticData.processedIds.includes(item.json.id));

console.log(`Received ${items.length} emails, ${newItems.length} new (${items.length - newItems.length} already processed)`);

if (newItems.length === 0) return [];
return newItems;

// Extract email details and parse request type from subject
const email = $input.first().json;
const subject = email.subject || '';

// Determine request type from subject line pattern
let requestType = 'New';
if (/^STR\s*\(Modified\)/i.test(subject)) {
  requestType = 'Modified';
} else if (/^STR\s*\(Cancell?ed\)/i.test(subject)) {
  requestType = 'Cancelled';
}

// Parse confirmId and tripCode from subject (needed for cancellation path)
const confirmIdMatch = subject.match(/Confirm\s*ID[:\s]+(\d+)/i);
const confirmId = confirmIdMatch ? confirmIdMatch[1] : '';
const tripCodeMatch = subject.match(/\|\s*([A-Z0-9]+(?:@[A-Z0-9]+)?)\s*\|/i);
const tripCode = tripCodeMatch ? tripCodeMatch[1] : '';

console.log(`Processing [${requestType}]: ${subject}`);
console.log(`  Confirm ID: ${confirmId}, Trip Code: ${tripCode}`);

return [{
  json: {
    messageId: email.id,
    subject: email.subject,
    receivedDateTime: email.receivedDateTime,
    hasAttachments: email.hasAttachments,
    requestType: requestType,
    confirmId: confirmId,
    tripCode: tripCode
  }
}];

// Build a minimal row for cancelled trip requests
// No PDF processing needed — just Confirm ID, status, and email timestamp
const item = $input.first().json;
const receivedDateTime = item.receivedDateTime || '';

console.log(`Formatting cancelled row: Confirm ID ${item.confirmId}`);

return [{
  json: {
    confirmId: item.confirmId || '',
    tripCode: item.tripCode || '',
    todaysDate: '',
    overnightTrip: '',
    startDate: '',
    endDate: '',
    startTime: '',
    endTime: '',
    destination: '',
    schoolName: '',
    address: '',
    atsDbn: '',
    district: '',
    region: '',
    requester: '',
    phone1: '',
    phone2: '',
    studentInitials: '',
    studentId: '',
    dob: '',
    medicalNeeds: '',
    driveUrl: '',
    requestType: 'Cancelled',
    emailReceived: receivedDateTime
  }
}];

// Find the securedoc HTML attachment
const attachments = $input.first().json.value || [];
const securedoc = attachments.find(a =>
  (a.name || '').toLowerCase().includes('securedoc')
);

if (!securedoc) {
  console.log('No securedoc attachment found — skipping email');
  return [];  // Empty = skip downstream nodes
}

const emailInfo = $('Log Email Details').first().json;
console.log(`Found: ${securedoc.name} (${(securedoc.size / 1024).toFixed(1)} KB)`);

return [{
  json: {
    messageId: emailInfo.messageId,
    emailSubject: emailInfo.subject,
    receivedDateTime: emailInfo.receivedDateTime,
    attachmentId: securedoc.id,
    attachmentName: securedoc.name,
    attachmentSize: securedoc.size
  }
}];

// Display the extracted trip fields for monitoring
const data = $input.first().json;
const trip = data.tripFields || {};
const studentCount = (data.students || []).length;

console.log(`Trip: ${trip.confirmId} | ${trip.tripCode} | ${trip.destination}`);
console.log(`Students: ${studentCount}`);

return [{
  json: {
    confirmId: trip.confirmId || '',
    tripCode: trip.tripCode || '',
    destination: trip.destination || '',
    schoolName: trip.schoolName || '',
    startDate: trip.startDate || '',
    endDate: trip.endDate || '',
    startTime: trip.startTime || '',
    endTime: trip.endTime || '',
    overnightTrip: trip.overnightTrip || '',
    studentCount: studentCount,
    driveUrl: data.driveUrl || '',
    pdfFilename: data.pdfFilename || '',
    // Pass through full data for next nodes
    _fullResponse: data
  }
}];

// Build single row with students as comma-separated arrays
const item = $input.first().json;
const data = item._fullResponse || item;
const tripFields = data.tripFields || {};
const students = data.students || [];
const driveUrl = data.driveUrl || item.driveUrl || '';
const receivedDateTime = $('Find Securedoc Attachment').first().json.receivedDateTime || '';

// Get requestType from Log Email Details (New or Modified)
const requestType = $('Log Email Details').first().json.requestType || 'New';

console.log(`Formatting ${students.length} student(s) as arrays [${requestType}]`);

return [{
  json: {
    confirmId: tripFields.confirmId || '',
    tripCode: tripFields.tripCode || '',
    todaysDate: tripFields.todaysDate || '',
    overnightTrip: tripFields.overnightTrip || '',
    startDate: tripFields.startDate || '',
    endDate: tripFields.endDate || '',
    startTime: tripFields.startTime || '',
    endTime: tripFields.endTime || '',
    destination: tripFields.destination || '',
    schoolName: tripFields.schoolName || '',
    address: tripFields.address || '',
    atsDbn: tripFields.atsDbn || '',
    district: tripFields.district || '',
    region: tripFields.region || '',
    requester: tripFields.requester || '',
    phone1: tripFields.phone1 || '',
    phone2: tripFields.phone2 || '',
    studentInitials: students.map(s => s.initials || '').join(', '),
    studentId: students.map(s => s.studentId || '').join(', '),
    dob: students.map(s => s.dob || '').join(', '),
    medicalNeeds: students.map(s => s.medicalNeeds || '').join(', '),
    driveUrl: driveUrl,
    requestType: requestType,
    emailReceived: receivedDateTime
  }
}];

// Mark this email as processed so it won't be re-processed next run
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedIds) staticData.processedIds = [];

const messageId = $('Log Email Details').first().json.messageId;
if (messageId && !staticData.processedIds.includes(messageId)) {
  staticData.processedIds.push(messageId);
  // Keep only last 200 IDs to prevent unbounded growth
  if (staticData.processedIds.length > 200) {
    staticData.processedIds = staticData.processedIds.slice(-200);
  }
}

console.log(`Marked ${messageId} as processed (${staticData.processedIds.length} total tracked)`);
return $input.all();

// Log the processing failure details
const result = $input.first().json;
const emailInfo = $('Find Securedoc Attachment').first().json;

console.error(`FAILED: ${emailInfo.emailSubject}`);
console.error(`Error: ${result.error || 'Unknown error'}`);

return [{
  json: {
    status: 'FAILED',
    emailSubject: emailInfo.emailSubject,
    messageId: emailInfo.messageId,
    error: result.error || 'Unknown processing error',
    elapsed: result.elapsed || '',
    timestamp: new Date().toISOString()
  }
}];
